// Validate and normalize AI agent output
const response = $input.first().json;

// Extract the agent output
let aiData = response.output || response.text || response;

// Parse if it's a JSON string
if (typeof aiData === 'string') {
  try {
    aiData = JSON.parse(aiData);
  } catch (e) {
    // Not valid JSON, treat as plain text
    aiData = { answer: aiData };
  }
}

// Validate required fields
const validated = {
  answer: aiData.answer || aiData.toString(),
  sources: Array.isArray(aiData.sources) ? aiData.sources : [],
  confidence: typeof aiData.confidence === 'number' ? aiData.confidence : 0.5,
  summary: aiData.summary || aiData.answer?.substring(0, 200) || ''
};

// Check if output meets quality standards
if (!validated.answer || validated.answer.length < 10) {
  throw new Error('AI output validation failed: answer too short or missing');
}

return validated;

// Process the validated AI response
const validated = $input.first().json;

return {
  processed: true,
  answer: validated.answer,
  summary: validated.summary,
  sources: validated.sources,
  confidence: validated.confidence,
  word_count: validated.answer.split(' ').length,
  timestamp: new Date().toISOString(),
  execution_id: $execution.id
};
